def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            if item > 0:
                priorities[i] = np.inf
            else:
                priorities[i] = 0
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        if ratio > 1:
            penalty_sum = 0
            for k in range(1, 5):
                penalty_sum += (ratio ** (2 * k + 1)) / (k * 3)
            priorities[i] = ratio ** 4 + penalty_sum
            if ratio > 2:
                priorities[i] += np.exp(ratio - 2)
            continue
        if 0 < ratio <= 1:
            score1 = 0
            for j in range(1, 7):
                sign = 1 if j % 3 == 0 else (-1)**j
                score1 += sign * (ratio ** j) / (j + 1)
            score2 = 0
            for m in range(1, 5):
                score2 += ((-1) ** m) * (ratio ** (m * 1.5)) / (m * 2)
            combined_score = abs(score1 + score2) * (12 if ratio < 0.25 else 8 if ratio < 0.5 else 4)
            if 0.75 < ratio <= 1:
                extrasum = 0
                for n in range(1, 6):
                    extrasum += (ratio ** n) / (n + 2) * ((-1) ** (n+1))
                combined_score += abs(extrasum)
            priorities[i] = combined_score
            continue
        if item == 0:
            priorities[i] = 0
        else:
            priorities[i] = np.inf
    for idx in range(len(priorities)):
        if not np.isinf(priorities[idx]) and priorities[idx] < 0.1:
            adjustment = 0
            for p in range(1, 10):
                adjustment += ((-1)**p) * np.sin(priorities[idx] * p * np.pi) / (p ** 2)
            priorities[idx] += abs(adjustment)
    return priorities
